import React from 'react';
import { useLocation } from 'react-router-dom';

export function MyTrip() {
  // Get the result data from the location state
  const location = useLocation();
  const tripResult = location.state?.tripResult;

  console.log("trip result:-", tripResult);

  return (
    <div className="py-8 w-11/12 mx-auto text-white bg-gray-800 rounded-lg shadow-md">
      <div>
        {/* Display the trip name */}
        <h1>{tripResult?.trip_name}</h1>
      </div>
    </div>
  );
}
